const crypto = require('crypto');
const items = $input.all();
const now = Date.now();
const cutoff = now - 24 * 60 * 60 * 1000;

const filtered = [];
const seen = new Set();

for (const item of items) {
  const raw = item.json;
  const dateStr = raw.pubDate || raw.isoDate || raw.date || raw.published || '';
  const pubDate = dateStr ? new Date(dateStr).getTime() : 0;
  if (pubDate < cutoff) continue;
  const title = (raw.title || '').trim();
  if (!title) continue;
  const hash = crypto.createHash('md5').update(title.toLowerCase()).digest('hex');
  if (seen.has(hash)) continue;
  seen.add(hash);
  filtered.push({ json: {
    titulo: title,
    url: raw.link || raw.guid || raw.id || '',
    descripcion: (raw.contentSnippet || raw.summary || raw.description || '').substring(0, 500),
    pubDate: new Date(pubDate).toISOString(),
    fuente: raw.feedTitle || 'RSS Feed',
    hash_titulo: hash
  }});
}

filtered.sort((a, b) => new Date(b.json.pubDate) - new Date(a.json.pubDate));
return filtered.slice(0, 10);

const articles = $('Filtrar 24h + Hash').all();
const existing = $input.all();

const existingHashes = new Set();
for (const rec of existing) {
  const h = rec.json.fields?.hash_titulo || rec.json.hash_titulo || '';
  if (h) existingHashes.add(h);
}

const newArticles = articles.filter(art => !existingHashes.has(art.json.hash_titulo));

if (newArticles.length === 0) {
  return [{ json: { continuar: false, mensaje: 'Sin noticias nuevas para carousel', count: 0 } }];
}

return newArticles.map(art => ({ json: { ...art.json, continuar: true } }));

const items = $input.all();

const lista = items.map((item, i) => {
  return (i+1) + '. TITULO: ' + item.json.titulo + '\n   URL: ' + item.json.url + '\n   DESCRIPCION: ' + item.json.descripcion + '\n   FECHA: ' + item.json.pubDate;
}).join('\n\n');

const articulos = items.map(i => ({
  titulo: i.json.titulo,
  url: i.json.url,
  descripcion: i.json.descripcion,
  pubDate: i.json.pubDate,
  hash_titulo: i.json.hash_titulo
}));

return [{ json: { noticias_formateadas: lista, cantidad: items.length, articulos_json: JSON.stringify(articulos) } }];

